use serde_json::json; use std::io::{self,BufRead,Write}; fn main()->anyhow::Result<()> { let stdin=io::stdin(); let mut stdout=io::stdout(); for line in stdin.lock().lines(){ let line=line?; let v:serde_json::Value=serde_json::from_str(&line).unwrap_or_else(|_| json!({"request_id":"unknown"})); let id=v.get("request_id").and_then(|x|x.as_str()).unwrap_or("unknown"); let out=json!({"request_id":id,"status":"ok","text":"{\"result\":[],\"stats\":{\"input_count\":0,\"output_count\":0}}","error_text":None::<String>,"extra":{"action":"transform_data"}}); writeln!(stdout,"{}",serde_json::to_string(&out)?)?; stdout.flush()?; } Ok(()) }
